-- Prompt 26 eligibility/window validation, locked finals and correction history.
begin;set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);
do $$declare comp_id uuid;division_id uuid;route_id uuid;begin comp_id:=public.save_competition('30000000-0000-4000-8000-000000000001',null,'Prompt 26 comp','Test',now()+interval'1 hour',now()+interval'3 hours',now()-interval'1 hour',now()+interval'30 minutes','registration',10::smallint,array['Open']);select division.id into division_id from public.competition_divisions division where division.competition_id=comp_id limit 1;route_id:=public.add_competition_route('30000000-0000-4000-8000-000000000001',comp_id,'70000000-0000-4000-8000-000000000001');perform set_config('test.competition',comp_id::text,true);perform set_config('test.division',division_id::text,true);perform set_config('test.competition_route',route_id::text,true);end$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);select public.register_for_competition('30000000-0000-4000-8000-000000000001',current_setting('test.competition')::uuid,current_setting('test.division')::uuid);
set local role service_role;update public.competitions set status='live',starts_at=now()-interval'10 minutes',ends_at=now()+interval'1 hour'where id=current_setting('test.competition')::uuid;
set local role authenticated;select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);select public.submit_competition_score('30000000-0000-4000-8000-000000000001',current_setting('test.competition')::uuid,current_setting('test.competition_route')::uuid,auth.uid(),true,true,2::smallint,null);
do $$begin begin perform public.submit_competition_score('30000000-0000-4000-8000-000000000001',current_setting('test.competition')::uuid,current_setting('test.competition_route')::uuid,auth.uid(),true,true,3::smallint,null);raise exception'Missing correction reason accepted';exception when others then if sqlerrm='Missing correction reason accepted'then raise;end if;end;end$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);select public.submit_competition_score('30000000-0000-4000-8000-000000000001',current_setting('test.competition')::uuid,current_setting('test.competition_route')::uuid,'10000000-0000-4000-8000-000000000004',true,true,1::smallint,'Judge correction');select public.finalize_competition('30000000-0000-4000-8000-000000000001',current_setting('test.competition')::uuid);
do $$begin if not exists(select 1 from public.score_entry_history where competition_id=current_setting('test.competition')::uuid and change_reason='Judge correction')then raise exception'Correction history missing';end if;begin perform public.submit_competition_score('30000000-0000-4000-8000-000000000001',current_setting('test.competition')::uuid,current_setting('test.competition_route')::uuid,'10000000-0000-4000-8000-000000000004',true,true,1::smallint,'After final');raise exception'Final score changed';exception when others then if sqlerrm='Final score changed'then raise;end if;end;update public.competitions set status='live'where id=current_setting('test.competition')::uuid;if exists(select 1 from public.competitions where id=current_setting('test.competition')::uuid and status='live')then raise exception'Final reopened directly';end if;end$$;
rollback;
